/** Identifier for a built-in T3 Code colour theme. */
export type ThemeId = "t3-dark" | "t3-light" | "t3-midnight";

/** Semantic colour slots every theme must define. */
export interface ThemeColors {
  /** Main application background. */
  background: string;
  /** Primary text / foreground colour. */
  foreground: string;
  /** Brand accent used for interactive elements (buttons, focus rings, links). */
  accent: string;
  /** Sidebar panel background. */
  sidebar: string;
  /** Code-editor area background. */
  editor: string;
  /** Integrated-terminal background. */
  terminal: string;
  /** Status-bar background at the bottom of the window. */
  statusBar: string;
}

/** A complete T3 Code colour theme definition. */
export interface Theme {
  readonly id: ThemeId;
  readonly name: string;
  /** Whether the theme uses a dark colour scheme (determines the `dark` CSS class). */
  readonly isDark: boolean;
  readonly colors: ThemeColors;
}

/** All built-in themes, ordered for display in the theme selector. */
export const BUILT_IN_THEMES: readonly Theme[] = [
  {
    id: "t3-dark",
    name: "T3 Dark",
    isDark: true,
    colors: {
      background: "#0d0d0d",
      foreground: "#f2f2f2",
      accent: "oklch(0.588 0.217 264)",
      sidebar: "#111111",
      editor: "#0a0a0a",
      terminal: "#0a0a0a",
      statusBar: "#111111",
    },
  },
  {
    id: "t3-light",
    name: "T3 Light",
    isDark: false,
    colors: {
      background: "#ffffff",
      foreground: "#262626",
      accent: "oklch(0.488 0.217 264)",
      sidebar: "#f5f5f5",
      editor: "#fafafa",
      terminal: "#1e1e1e",
      statusBar: "#efefef",
    },
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    isDark: true,
    colors: {
      background: "#020205",
      foreground: "#e2e2f0",
      accent: "oklch(0.65 0.22 280)",
      sidebar: "#06060c",
      editor: "#020205",
      terminal: "#020205",
      statusBar: "#08080f",
    },
  },
] as const;

/** Default theme ID applied when no preference is stored in localStorage. */
export const DEFAULT_THEME_ID: ThemeId = "t3-dark";

/** Look up a built-in theme by its ID. Returns `undefined` if not found. */
export function getThemeById(id: string): Theme | undefined {
  return BUILT_IN_THEMES.find((t) => t.id === id);
}

