import { BUILT_IN_THEMES, type ThemeId } from "@t3tools/shared/theme";
import { useColorTheme } from "~/providers/ThemeProvider";

/**
 * Theme selector with colour-swatch previews.
 * Must be rendered inside a ThemeProvider.
 */
export function ThemeSelector() {
  const { colorTheme, setColorTheme } = useColorTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Colour theme">
      {BUILT_IN_THEMES.map((theme) => {
        const selected = colorTheme.id === theme.id;
        return (
          <button
            key={theme.id}
            type="button"
            role="radio"
            aria-checked={selected}
            onClick={() => setColorTheme(theme.id as ThemeId)}
            className={`flex w-full items-center justify-between rounded-lg border px-3 py-2.5 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
          >
            <span className="flex items-center gap-3">
              {/* Colour swatches: background / accent / sidebar */}
              <span className="flex gap-1" aria-hidden="true">
                <ColorSwatch color={theme.colors.background} label="background" />
                <ColorSwatch color={theme.colors.accent} label="accent" />
                <ColorSwatch color={theme.colors.sidebar} label="sidebar" />
              </span>

              <span className="flex flex-col gap-0.5">
                <span className="text-sm font-medium leading-none">{theme.name}</span>
                <span className="text-xs leading-none opacity-60">
                  {theme.isDark ? "Dark" : "Light"}
                </span>
              </span>
            </span>

            {selected && (
              <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Active
              </span>
            )}
          </button>
        );
      })}
    </div>
  );
}

// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------

function ColorSwatch({ color, label }: { color: string; label: string }) {
  return (
    <span
      aria-label={label}
      className="block size-4 rounded-full border border-black/10"
      style={{ background: color }}
    />
  );
}

