import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useState,
  type ReactNode,
} from "react";
import { BUILT_IN_THEMES, DEFAULT_THEME_ID, getThemeById, type Theme, type ThemeId } from "@t3tools/shared/theme";

// ---------------------------------------------------------------------------
// Context
// ---------------------------------------------------------------------------

interface ThemeContextValue {
  /** The currently active colour theme. */
  colorTheme: Theme;
  /** Persist and apply a new colour theme by ID. */
  setColorTheme: (id: ThemeId) => void;
}

const ThemeContext = createContext<ThemeContextValue | null>(null);

// ---------------------------------------------------------------------------
// Storage
// ---------------------------------------------------------------------------

const STORAGE_KEY = "t3code:color-theme";

function readStoredThemeId(): ThemeId {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (raw !== null && getThemeById(raw) !== undefined) return raw as ThemeId;
  } catch {
    // Ignore storage access errors (e.g. in restricted contexts).
  }
  return DEFAULT_THEME_ID;
}

// ---------------------------------------------------------------------------
// DOM application
// ---------------------------------------------------------------------------

function applyColorTheme(theme: Theme, suppressTransitions = false): void {
  const root = document.documentElement;

  if (suppressTransitions) {
    root.classList.add("no-transitions");
  }

  // Toggle the dark-mode class so @variant dark rules stay in sync.
  root.classList.toggle("dark", theme.isDark);

  // Core semantic variables — override any CSS-rule-level declarations.
  root.style.setProperty("--background", theme.colors.background);
  root.style.setProperty("--foreground", theme.colors.foreground);
  root.style.setProperty("--primary", theme.colors.accent);
  root.style.setProperty("--ring", theme.colors.accent);

  // Domain-specific theme variables consumed by layout components.
  root.style.setProperty("--theme-background", theme.colors.background);
  root.style.setProperty("--theme-foreground", theme.colors.foreground);
  root.style.setProperty("--theme-accent", theme.colors.accent);
  root.style.setProperty("--theme-sidebar", theme.colors.sidebar);
  root.style.setProperty("--theme-editor", theme.colors.editor);
  root.style.setProperty("--theme-terminal", theme.colors.terminal);
  root.style.setProperty("--theme-status-bar", theme.colors.statusBar);

  if (suppressTransitions) {
    // Force a reflow so no-transitions takes effect before removal.
    // oxlint-disable-next-line no-unused-expressions
    void root.offsetHeight;
    requestAnimationFrame(() => {
      root.classList.remove("no-transitions");
    });
  }
}

// Apply synchronously at module load to prevent colour flash before React
// renders. This mirrors the pattern used by the light/dark useTheme hook.
applyColorTheme(getThemeById(readStoredThemeId()) ?? (BUILT_IN_THEMES[0] as Theme));

// ---------------------------------------------------------------------------
// Provider
// ---------------------------------------------------------------------------

export function ThemeProvider({ children }: { children: ReactNode }) {
  const [colorThemeId, setColorThemeId] = useState<ThemeId>(readStoredThemeId);

  const colorTheme = useMemo(
    () => getThemeById(colorThemeId) ?? (BUILT_IN_THEMES[0] as Theme),
    [colorThemeId],
  );

  const setColorTheme = useCallback((id: ThemeId) => {
    const theme = getThemeById(id);
    if (theme === undefined) return;
    try {
      localStorage.setItem(STORAGE_KEY, id);
    } catch {
      // Ignore storage access errors.
    }
    applyColorTheme(theme, true);
    setColorThemeId(id);
  }, []);

  // Re-apply on every render cycle that changes the theme (handles HMR).
  useEffect(() => {
    applyColorTheme(colorTheme);
  }, [colorTheme]);

  const value = useMemo(
    () => ({ colorTheme, setColorTheme }),
    [colorTheme, setColorTheme],
  );

  return <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>;
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

/** Access the active colour theme and the setter from within a ThemeProvider. */
export function useColorTheme(): ThemeContextValue {
  const ctx = useContext(ThemeContext);
  if (ctx === null) {
    throw new Error("useColorTheme must be used within a ThemeProvider");
  }
  return ctx;
}

